const item = $input.first().json;
const fields = item.fields || item;

const reviewerName = (fields['Reviewer Name'] || fields.reviewer_name || 'Happy Customer').trim();
const reviewText   = (fields['Review Text']   || fields.review_text   || '').trim();
const rating       = Number(fields['Rating']  || fields.rating || 5);
const source       = (fields['Source']        || fields.source || 'Verified Review').trim();
const recordId     = item.id || item.record_id || '';

if (!reviewText) throw new Error('Review text is empty. Check your Google Sheet column names.');

const cardText = reviewText.length > 200 ? reviewText.substring(0, 197) + '...' : reviewText;
const captionText = reviewText.length > 280 ? reviewText.substring(0, 277) + '...' : reviewText;
const starCount = Math.min(Math.max(rating, 1), 5);
const starsText = Array(starCount + 1).join('5star ');
const hashtags = '#customerreview #5stars #testimonial #socialproof #happycustomer #review';

const finalCaption = [
  '(' + starCount + '/5) Real words from a real customer.',
  '',
  '"' + captionText + '"',
  '-- ' + reviewerName + ' via ' + source,
  '',
  'See why our customers keep coming back.',
  'Link in bio.',
  '',
  hashtags,
].join('\n').trim().substring(0, 2200);

console.log('[Prep] Reviewer:', reviewerName, 'Rating:', rating);

return [{
  json: {
    record_id:     recordId,
    reviewer_name: reviewerName,
    review_text:   reviewText,
    card_text:     cardText,
    rating:        rating,
    star_count:    starCount,
    source:        source,
    final_caption: finalCaption,
    ig_user_id:    $env.IG_USER_ID,
  }
}];

const uploadResult = $input.first().json;
const prepData = $('Code Prepare Fields').first().json;

const publicImageUrl =
  uploadResult.public_url ||
  uploadResult.url        ||
  uploadResult.file_url   ||
  uploadResult.cdn_url    ||
  uploadResult.imageUrl   ||
  '';

if (!publicImageUrl) {
  throw new Error('Upload to URL returned no public URL. Keys: ' + JSON.stringify(Object.keys(uploadResult)));
}

return [{
  json: {
    public_image_url: publicImageUrl,
    final_caption:    prepData.final_caption,
    ig_user_id:       prepData.ig_user_id,
    record_id:        prepData.record_id,
    reviewer_name:    prepData.reviewer_name,
    review_text:      prepData.review_text,
    source:           prepData.source,
  }
}];

